INSERT INTO tracks (title, slug, description, icon, order_index, is_published) VALUES ('Cognitive Biases 101', 'cognitive-biases-101', 'Learn to spot the mental shortcuts that quietly distort your judgment — and how to catch yourself in the act.', 'brain', 1, 1);
INSERT INTO lessons (track_id, title, order_index, xp_reward, mastery_threshold) VALUES ((SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'), 'Confirmation Bias', 1, 10, 70);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'You believe a certain diet is healthy. You start noticing articles that support this and skim past ones that don''t. What is this an example of?', 'This is confirmation bias — the tendency to search for, interpret, and recall information in a way that confirms beliefs we already hold, while giving less attention to information that contradicts them.', 'Nickerson, R. S. (1998). Confirmation bias: A ubiquitous phenomenon in many guises. Review of General Psychology.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'You believe a certain diet is healthy. You start noticing articles that support this and skim past ones that don''t. What is this an example of?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Confirmation bias', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'You believe a certain diet is healthy. You start noticing articles that support this and skim past ones that don''t. What is this an example of?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Anchoring bias', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'You believe a certain diet is healthy. You start noticing articles that support this and skim past ones that don''t. What is this an example of?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Sunk cost fallacy', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'You believe a certain diet is healthy. You start noticing articles that support this and skim past ones that don''t. What is this an example of?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Availability heuristic', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'Confirmation bias is best described as a problem with which part of thinking?', 'It''s a problem of selective information gathering and interpretation, not a memory defect or a logic error in itself — we actively (often unconsciously) steer ourselves toward evidence that fits what we already believe.', 'Nickerson, R. S. (1998). Confirmation bias: A ubiquitous phenomenon in many guises. Review of General Psychology.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Confirmation bias is best described as a problem with which part of thinking?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'How we seek and weigh evidence', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Confirmation bias is best described as a problem with which part of thinking?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'How we store long-term memories', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Confirmation bias is best described as a problem with which part of thinking?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'How fast we can do arithmetic', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Confirmation bias is best described as a problem with which part of thinking?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'How well we recognize faces', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'scenario', 'A manager is convinced a new hire is a poor performer. She starts scrutinizing the hire''s mistakes closely but barely notices their successes. What''s happening?', 'This is confirmation bias in action — once a belief (''this hire is bad'') is formed, we tend to notice and weigh evidence that fits it more heavily than evidence that doesn''t, reinforcing the original belief regardless of its accuracy.', 'Nickerson, R. S. (1998). Confirmation bias: A ubiquitous phenomenon in many guises. Review of General Psychology.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A manager is convinced a new hire is a poor performer. She starts scrutinizing the hire''s mistakes closely but barely notices their successes. What''s happening?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'The manager is confirming her existing belief', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A manager is convinced a new hire is a poor performer. She starts scrutinizing the hire''s mistakes closely but barely notices their successes. What''s happening?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'The manager is anchoring on a number', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A manager is convinced a new hire is a poor performer. She starts scrutinizing the hire''s mistakes closely but barely notices their successes. What''s happening?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'The manager is falling for the sunk cost fallacy', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A manager is convinced a new hire is a poor performer. She starts scrutinizing the hire''s mistakes closely but barely notices their successes. What''s happening?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'The manager is showing the availability heuristic', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'Which of these is the best way to actively counter confirmation bias when researching a decision?', 'Deliberately seeking out disconfirming evidence — sometimes called a ''devil''s advocate'' approach — is one of the few reliably effective countermeasures, because it forces attention onto information you''d otherwise skip.', 'Lord, C. G., Lepper, M. R., & Preston, E. (1984). Considering the opposite: A corrective strategy for social judgment. Journal of Personality and Social Psychology.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of these is the best way to actively counter confirmation bias when researching a decision?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Deliberately search for evidence that contradicts your view', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of these is the best way to actively counter confirmation bias when researching a decision?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Read more articles that agree with your view, to be thorough', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of these is the best way to actively counter confirmation bias when researching a decision?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Trust your gut instinct instead of researching', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of these is the best way to actively counter confirmation bias when researching a decision?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Ask only people who already agree with you', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'Social media feeds that show you more of what you already engage with can strengthen confirmation bias. Why?', 'Algorithmic feeds amplify confirmation bias by consistently surfacing content that matches existing engagement patterns, narrowing the range of perspectives a person is exposed to over time.', 'Nickerson, R. S. (1998). Confirmation bias: A ubiquitous phenomenon in many guises. Review of General Psychology.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Social media feeds that show you more of what you already engage with can strengthen confirmation bias. Why?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'They repeatedly surface content that matches what you already believe', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Social media feeds that show you more of what you already engage with can strengthen confirmation bias. Why?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'They show completely random content', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Social media feeds that show you more of what you already engage with can strengthen confirmation bias. Why?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'They prioritize the oldest posts first', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Social media feeds that show you more of what you already engage with can strengthen confirmation bias. Why?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'They only show content from verified accounts', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'In a debate, confirmation bias can make people rate the SAME argument as stronger or weaker depending on what?', 'Research on motivated reasoning shows people judge argument quality partly based on whether the conclusion matches their prior beliefs — the same argument is rated as more convincing when it supports what someone already thinks.', 'Nickerson, R. S. (1998). Confirmation bias: A ubiquitous phenomenon in many guises. Review of General Psychology.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'In a debate, confirmation bias can make people rate the SAME argument as stronger or weaker depending on what?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Whether the conclusion matches their existing belief', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'In a debate, confirmation bias can make people rate the SAME argument as stronger or weaker depending on what?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'The font the argument is printed in', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'In a debate, confirmation bias can make people rate the SAME argument as stronger or weaker depending on what?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'How long the argument took to read', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'In a debate, confirmation bias can make people rate the SAME argument as stronger or weaker depending on what?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'The time of day the argument was heard', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'A juror decides early in a trial that the defendant is guilty, then interprets ambiguous testimony as further proof of guilt. This is an example of confirmation bias affecting what?', 'This shows confirmation bias distorting the interpretation of ambiguous evidence — the same testimony could reasonably support multiple conclusions, but it gets read through the lens of the belief already formed.', 'Nickerson, R. S. (1998). Confirmation bias: A ubiquitous phenomenon in many guises. Review of General Psychology.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A juror decides early in a trial that the defendant is guilty, then interprets ambiguous testimony as further proof of guilt. This is an example of confirmation bias affecting what?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Interpretation of ambiguous evidence', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A juror decides early in a trial that the defendant is guilty, then interprets ambiguous testimony as further proof of guilt. This is an example of confirmation bias affecting what?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'The juror''s memory of their own birthday', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A juror decides early in a trial that the defendant is guilty, then interprets ambiguous testimony as further proof of guilt. This is an example of confirmation bias affecting what?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'The courtroom''s physical layout', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A juror decides early in a trial that the defendant is guilty, then interprets ambiguous testimony as further proof of guilt. This is an example of confirmation bias affecting what?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'The length of the jury deliberation', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'Which statement about confirmation bias is TRUE?', 'Confirmation bias affects virtually everyone, including trained experts and scientists — awareness of it reduces but doesn''t eliminate it, which is exactly why structured countermeasures like seeking disconfirming evidence matter.', 'Nickerson, R. S. (1998). Confirmation bias: A ubiquitous phenomenon in many guises. Review of General Psychology.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which statement about confirmation bias is TRUE?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'It affects nearly everyone, including experts, to some degree', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which statement about confirmation bias is TRUE?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'It only affects people with low intelligence', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which statement about confirmation bias is TRUE?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'It disappears completely once you learn about it', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which statement about confirmation bias is TRUE?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Confirmation Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'It only happens in political discussions', 0, 3);
INSERT INTO lessons (track_id, title, order_index, xp_reward, mastery_threshold) VALUES ((SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'), 'Anchoring Bias', 2, 10, 70);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'A store lists a jacket''s ''original price'' as $200, now on sale for $90. Even if $200 was never a real selling price, shoppers often perceive $90 as a great deal. What''s this an example of?', 'This is anchoring bias — the first number we see (the ''anchor'') skews our judgment of what follows, even when we know the anchor may be arbitrary or manipulated.', 'Tversky, A., & Kahneman, D. (1974). Judgment under uncertainty: Heuristics and biases. Science.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A store lists a jacket''s ''original price'' as $200, now on sale for $90. Even if $200 was never a real selling price, shoppers often perceive $90 as a great deal. What''s this an example of?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Anchoring bias', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A store lists a jacket''s ''original price'' as $200, now on sale for $90. Even if $200 was never a real selling price, shoppers often perceive $90 as a great deal. What''s this an example of?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Confirmation bias', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A store lists a jacket''s ''original price'' as $200, now on sale for $90. Even if $200 was never a real selling price, shoppers often perceive $90 as a great deal. What''s this an example of?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Availability heuristic', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A store lists a jacket''s ''original price'' as $200, now on sale for $90. Even if $200 was never a real selling price, shoppers often perceive $90 as a great deal. What''s this an example of?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Dunning-Kruger effect', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'In salary negotiations, why does whoever states the first number often have an advantage?', 'The first number offered acts as an anchor that pulls the rest of the negotiation toward it — even skilled negotiators tend to adjust from that anchor rather than ignore it entirely.', 'Galinsky, A. D., & Mussweiler, T. (2001). First offers as anchors: The role of perspective-taking and negotiator focus. Journal of Personality and Social Psychology.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'In salary negotiations, why does whoever states the first number often have an advantage?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'It sets an anchor that pulls the rest of the negotiation toward it', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'In salary negotiations, why does whoever states the first number often have an advantage?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'It legally locks in that exact number', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'In salary negotiations, why does whoever states the first number often have an advantage?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'It''s always the fairest number', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'In salary negotiations, why does whoever states the first number often have an advantage?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'It ends the negotiation immediately', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'scenario', 'In a classic study, people were shown a spinning wheel rigged to land on either 10 or 65, then asked to estimate the percentage of African countries in the UN. Those who saw ''65'' guessed higher than those who saw ''10'' — even though the wheel was clearly random. What does this show?', 'This famous experiment showed that even an obviously irrelevant, random number can act as an anchor and shift numeric estimates, demonstrating how automatic and hard to resist anchoring effects are.', 'Tversky, A., & Kahneman, D. (1974). Judgment under uncertainty: Heuristics and biases. Science.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'In a classic study, people were shown a spinning wheel rigged to land on either 10 or 65, then asked to estimate the percentage of African countries in the UN. Those who saw ''65'' guessed higher than those who saw ''10'' — even though the wheel was clearly random. What does this show?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Even a random, irrelevant number can anchor our estimates', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'In a classic study, people were shown a spinning wheel rigged to land on either 10 or 65, then asked to estimate the percentage of African countries in the UN. Those who saw ''65'' guessed higher than those who saw ''10'' — even though the wheel was clearly random. What does this show?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'People are generally bad at spinning wheels', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'In a classic study, people were shown a spinning wheel rigged to land on either 10 or 65, then asked to estimate the percentage of African countries in the UN. Those who saw ''65'' guessed higher than those who saw ''10'' — even though the wheel was clearly random. What does this show?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'People always ignore irrelevant information', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'In a classic study, people were shown a spinning wheel rigged to land on either 10 or 65, then asked to estimate the percentage of African countries in the UN. Those who saw ''65'' guessed higher than those who saw ''10'' — even though the wheel was clearly random. What does this show?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'This demonstrates the sunk cost fallacy', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'Which strategy is most supported by research for reducing anchoring effects in a negotiation?', 'Coming prepared with your own independent research and a target range helps counteract an anchor, because you have a reference point that didn''t originate from the other party''s opening offer.', 'Galinsky, A. D., & Mussweiler, T. (2001). First offers as anchors: The role of perspective-taking and negotiator focus. Journal of Personality and Social Psychology.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which strategy is most supported by research for reducing anchoring effects in a negotiation?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Research your own target range before the negotiation starts', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which strategy is most supported by research for reducing anchoring effects in a negotiation?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Always accept the first offer you hear', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which strategy is most supported by research for reducing anchoring effects in a negotiation?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Avoid thinking about numbers until the very end', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which strategy is most supported by research for reducing anchoring effects in a negotiation?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Let the other party set every number', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'A real estate agent shows a house priced unrealistically high right before showing the one they actually want to sell you, at a ''better'' price. This tactic relies on which bias?', 'This is a deliberate use of anchoring — the inflated first price resets your mental reference point, making the actual target price look more reasonable by comparison.', 'Tversky, A., & Kahneman, D. (1974). Judgment under uncertainty: Heuristics and biases. Science.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A real estate agent shows a house priced unrealistically high right before showing the one they actually want to sell you, at a ''better'' price. This tactic relies on which bias?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Anchoring bias', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A real estate agent shows a house priced unrealistically high right before showing the one they actually want to sell you, at a ''better'' price. This tactic relies on which bias?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Sunk cost fallacy', 0, 1);
