INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A real estate agent shows a house priced unrealistically high right before showing the one they actually want to sell you, at a ''better'' price. This tactic relies on which bias?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Availability heuristic', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'Does simply knowing about anchoring bias make you immune to it?', 'Research consistently finds that anchoring effects persist even in people who are explicitly warned about them or are experts in the relevant field — awareness helps but doesn''t fully eliminate the effect.', 'Tversky, A., & Kahneman, D. (1974). Judgment under uncertainty: Heuristics and biases. Science.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Does simply knowing about anchoring bias make you immune to it?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'No — the effect persists even when you''re aware of it', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Does simply knowing about anchoring bias make you immune to it?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Yes — awareness completely eliminates it', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Does simply knowing about anchoring bias make you immune to it?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Yes, but only for numerical estimates', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Does simply knowing about anchoring bias make you immune to it?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'No one has studied this question', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'A restaurant menu lists a $120 bottle of wine next to a $45 one. Sales of the $45 bottle often increase. Why?', 'The expensive item serves as an anchor, making the mid-priced item look like a comparatively reasonable choice — a common technique in menu and pricing design.', 'Tversky, A., & Kahneman, D. (1974). Judgment under uncertainty: Heuristics and biases. Science.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A restaurant menu lists a $120 bottle of wine next to a $45 one. Sales of the $45 bottle often increase. Why?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'The $120 bottle anchors expectations, making $45 seem reasonable', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A restaurant menu lists a $120 bottle of wine next to a $45 one. Sales of the $45 bottle often increase. Why?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'The $45 bottle is always objectively the best wine', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A restaurant menu lists a $120 bottle of wine next to a $45 one. Sales of the $45 bottle often increase. Why?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'People always choose the cheapest item on a menu', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A restaurant menu lists a $120 bottle of wine next to a $45 one. Sales of the $45 bottle often increase. Why?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'This has nothing to do with pricing psychology', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'Which of the following is the clearest example of anchoring bias at play?', 'Estimating a car''s fair price from the sticker price is a textbook anchoring scenario — the sticker number becomes the reference point your estimate adjusts from, even if it isn''t the true market value.', 'Tversky, A., & Kahneman, D. (1974). Judgment under uncertainty: Heuristics and biases. Science.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of the following is the clearest example of anchoring bias at play?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Guessing a used car''s fair price based on the sticker price you saw first', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of the following is the clearest example of anchoring bias at play?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Remembering a car crash you saw on the news', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of the following is the clearest example of anchoring bias at play?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Refusing to sell a car because you already paid for repairs', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of the following is the clearest example of anchoring bias at play?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Anchoring Bias' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Believing you''re a better driver than average', 0, 3);
INSERT INTO lessons (track_id, title, order_index, xp_reward, mastery_threshold) VALUES ((SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'), 'Availability Heuristic', 3, 10, 70);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'After seeing news coverage of a plane crash, many people temporarily overestimate how dangerous flying is, compared to statistically safer activities like driving. What is this an example of?', 'This is the availability heuristic — we judge the likelihood of an event by how easily examples come to mind, and vivid, widely-covered events like plane crashes are far more memorable than everyday risks like car accidents.', 'Tversky, A., & Kahneman, D. (1973). Availability: A heuristic for judging frequency and probability. Cognitive Psychology.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'After seeing news coverage of a plane crash, many people temporarily overestimate how dangerous flying is, compared to statistically safer activities like driving. What is this an example of?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Availability heuristic', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'After seeing news coverage of a plane crash, many people temporarily overestimate how dangerous flying is, compared to statistically safer activities like driving. What is this an example of?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Anchoring bias', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'After seeing news coverage of a plane crash, many people temporarily overestimate how dangerous flying is, compared to statistically safer activities like driving. What is this an example of?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Sunk cost fallacy', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'After seeing news coverage of a plane crash, many people temporarily overestimate how dangerous flying is, compared to statistically safer activities like driving. What is this an example of?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Confirmation bias', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'The availability heuristic is best described as judging probability based on what?', 'The core mechanism is ease of recall — not actual statistical frequency. Anything that makes an example more memorable (vividness, recency, emotional impact) makes it feel more common, whether or not it actually is.', 'Tversky, A., & Kahneman, D. (1973). Availability: A heuristic for judging frequency and probability. Cognitive Psychology.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'The availability heuristic is best described as judging probability based on what?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'How easily examples come to mind', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'The availability heuristic is best described as judging probability based on what?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Official government statistics', 0, 1);
