INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'The availability heuristic is best described as judging probability based on what?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Peer-reviewed research only', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'scenario', 'A person who just watched a documentary about shark attacks refuses to swim in the ocean the next day, despite shark attacks being extremely rare. What''s driving this decision?', 'The documentary made shark attacks highly ''available'' in memory — vivid and recent — which distorts the perceived risk far above the actual statistical likelihood.', 'Tversky, A., & Kahneman, D. (1973). Availability: A heuristic for judging frequency and probability. Cognitive Psychology.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A person who just watched a documentary about shark attacks refuses to swim in the ocean the next day, despite shark attacks being extremely rare. What''s driving this decision?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'The availability heuristic, from a recent vivid example', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A person who just watched a documentary about shark attacks refuses to swim in the ocean the next day, despite shark attacks being extremely rare. What''s driving this decision?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Accurate statistical reasoning', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A person who just watched a documentary about shark attacks refuses to swim in the ocean the next day, despite shark attacks being extremely rare. What''s driving this decision?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'The sunk cost fallacy', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A person who just watched a documentary about shark attacks refuses to swim in the ocean the next day, despite shark attacks being extremely rare. What''s driving this decision?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'The Dunning-Kruger effect', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'Which of these would make an event feel MORE ''available'' in memory, even if its actual frequency stays the same?', 'Emotional intensity is one of the strongest drivers of availability — a single dramatic, emotionally charged event can outweigh dozens of mundane statistics in how ''common'' something feels.', 'Tversky, A., & Kahneman, D. (1973). Availability: A heuristic for judging frequency and probability. Cognitive Psychology.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of these would make an event feel MORE ''available'' in memory, even if its actual frequency stays the same?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'The event being emotionally intense or dramatic', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of these would make an event feel MORE ''available'' in memory, even if its actual frequency stays the same?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'The event happening in a country you''ve never visited', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of these would make an event feel MORE ''available'' in memory, even if its actual frequency stays the same?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'The event being reported without any images', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of these would make an event feel MORE ''available'' in memory, even if its actual frequency stays the same?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'The event happening exactly 10 years ago', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'A hiring manager recalls one bad experience with a hire from a certain university and now assumes graduates from that school are generally unreliable. What is this?', 'A single memorable case being generalized into a broader belief is a classic availability heuristic pattern — one vivid data point outweighs the (unseen) larger pool of graduates who performed fine.', 'Tversky, A., & Kahneman, D. (1973). Availability: A heuristic for judging frequency and probability. Cognitive Psychology.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A hiring manager recalls one bad experience with a hire from a certain university and now assumes graduates from that school are generally unreliable. What is this?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Availability heuristic', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A hiring manager recalls one bad experience with a hire from a certain university and now assumes graduates from that school are generally unreliable. What is this?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Anchoring bias', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A hiring manager recalls one bad experience with a hire from a certain university and now assumes graduates from that school are generally unreliable. What is this?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Sunk cost fallacy', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A hiring manager recalls one bad experience with a hire from a certain university and now assumes graduates from that school are generally unreliable. What is this?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Dunning-Kruger effect', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'Which is a healthy way to counteract the availability heuristic when assessing real-world risk?', 'Deliberately seeking out base-rate statistics — actual frequency data — helps correct for the distortion caused by vivid, memorable, but statistically rare examples.', 'Tversky, A., & Kahneman, D. (1973). Availability: A heuristic for judging frequency and probability. Cognitive Psychology.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which is a healthy way to counteract the availability heuristic when assessing real-world risk?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Look up actual base-rate statistics instead of relying on memory', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which is a healthy way to counteract the availability heuristic when assessing real-world risk?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Only watch more news coverage of the topic', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which is a healthy way to counteract the availability heuristic when assessing real-world risk?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Trust whichever example comes to mind first', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which is a healthy way to counteract the availability heuristic when assessing real-world risk?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Ask only people who share your existing view', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'People often think words starting with the letter ''K'' are more common than words with ''K'' as the third letter, even though the opposite is true. Why?', 'This is a classic demonstration of the availability heuristic — it''s much easier to mentally search for words by their first letter than their third, so first-letter-K words feel more ''available'' and thus seem more frequent.', 'Tversky, A., & Kahneman, D. (1973). Availability: A heuristic for judging frequency and probability. Cognitive Psychology.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'People often think words starting with the letter ''K'' are more common than words with ''K'' as the third letter, even though the opposite is true. Why?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'It''s easier to recall words by their first letter than a middle letter', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'People often think words starting with the letter ''K'' are more common than words with ''K'' as the third letter, even though the opposite is true. Why?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Words with ''K'' first are always shorter', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'People often think words starting with the letter ''K'' are more common than words with ''K'' as the third letter, even though the opposite is true. Why?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'This is just a coincidence with no explanation', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'People often think words starting with the letter ''K'' are more common than words with ''K'' as the third letter, even though the opposite is true. Why?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'People are anchoring on the letter K', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'Which statement about the availability heuristic is most accurate?', 'The availability heuristic is generally a useful mental shortcut — most of the time, things that happen often really are easier to recall. It becomes a problem specifically when recall ease and actual frequency diverge, like with rare-but-vivid events.', 'Tversky, A., & Kahneman, D. (1973). Availability: A heuristic for judging frequency and probability. Cognitive Psychology.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which statement about the availability heuristic is most accurate?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'It''s a useful shortcut that fails mainly when memorable events are actually rare', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which statement about the availability heuristic is most accurate?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'It is always wrong and never useful', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which statement about the availability heuristic is most accurate?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'It only applies to financial decisions', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which statement about the availability heuristic is most accurate?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Availability Heuristic' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'It was disproven by later research', 0, 3);
INSERT INTO lessons (track_id, title, order_index, xp_reward, mastery_threshold) VALUES ((SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'), 'Sunk Cost Fallacy', 4, 10, 70);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'Someone keeps watching a movie they''re not enjoying because they''ve ''already invested an hour'' into it. What is this an example of?', 'This is the sunk cost fallacy — continuing a behavior because of resources (time, money, effort) already spent, even though those resources can''t be recovered and shouldn''t factor into a rational decision about what to do next.', 'Arkes, H. R., & Blumer, C. (1985). The psychology of sunk cost. Organizational Behavior and Human Decision Processes.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Someone keeps watching a movie they''re not enjoying because they''ve ''already invested an hour'' into it. What is this an example of?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Sunk cost fallacy', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Someone keeps watching a movie they''re not enjoying because they''ve ''already invested an hour'' into it. What is this an example of?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Anchoring bias', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Someone keeps watching a movie they''re not enjoying because they''ve ''already invested an hour'' into it. What is this an example of?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Availability heuristic', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Someone keeps watching a movie they''re not enjoying because they''ve ''already invested an hour'' into it. What is this an example of?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Confirmation bias', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'From a purely rational decision-making standpoint, how should past, unrecoverable costs factor into a future decision?', 'Standard rational-choice theory says sunk costs are irrelevant to future decisions — only the costs and benefits going forward should matter, since past spending can''t be changed no matter what you choose now.', 'Arkes, H. R., & Blumer, C. (1985). The psychology of sunk cost. Organizational Behavior and Human Decision Processes.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'From a purely rational decision-making standpoint, how should past, unrecoverable costs factor into a future decision?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'They shouldn''t factor in at all — only future costs/benefits matter', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'From a purely rational decision-making standpoint, how should past, unrecoverable costs factor into a future decision?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'They should be the main deciding factor', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'From a purely rational decision-making standpoint, how should past, unrecoverable costs factor into a future decision?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'They should be doubled in importance', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'From a purely rational decision-making standpoint, how should past, unrecoverable costs factor into a future decision?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'They should only matter for money, not time', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'scenario', 'A company has spent $2 million on a failing project. Executives argue ''we can''t stop now, we''ve already put in $2 million'' and approve more funding. What''s happening here?', 'This is a classic organizational example of the sunk cost fallacy — the decision to continue is being driven by past spending rather than an honest assessment of whether future investment is worthwhile.', 'Arkes, H. R., & Blumer, C. (1985). The psychology of sunk cost. Organizational Behavior and Human Decision Processes.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A company has spent $2 million on a failing project. Executives argue ''we can''t stop now, we''ve already put in $2 million'' and approve more funding. What''s happening here?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'The sunk cost fallacy is driving the decision', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A company has spent $2 million on a failing project. Executives argue ''we can''t stop now, we''ve already put in $2 million'' and approve more funding. What''s happening here?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'This is a purely rational business decision', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A company has spent $2 million on a failing project. Executives argue ''we can''t stop now, we''ve already put in $2 million'' and approve more funding. What''s happening here?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'This is an example of anchoring bias', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A company has spent $2 million on a failing project. Executives argue ''we can''t stop now, we''ve already put in $2 million'' and approve more funding. What''s happening here?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'This is an example of the availability heuristic', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'Which question best helps someone check whether they''re falling for the sunk cost fallacy?', 'Reframing the decision as a fresh choice — ignoring what''s already been spent — strips out the sunk cost and forces a decision based only on future value, which is the rational way to evaluate it.', 'Arkes, H. R., & Blumer, C. (1985). The psychology of sunk cost. Organizational Behavior and Human Decision Processes.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which question best helps someone check whether they''re falling for the sunk cost fallacy?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), '''If I were starting fresh today, knowing what I know now, would I choose this?''', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which question best helps someone check whether they''re falling for the sunk cost fallacy?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), '''How much have I already spent on this?''', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which question best helps someone check whether they''re falling for the sunk cost fallacy?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), '''How would I feel if I quit right now?''', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which question best helps someone check whether they''re falling for the sunk cost fallacy?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), '''What would my friends think if I quit?''', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'A person stays in a relationship they''re unhappy in, thinking ''I''ve already put five years into this.'' What bias does this reasoning reflect?', 'Time already invested in a relationship is a sunk cost — it can''t be recovered regardless of what happens next, so basing the decision on it (rather than on current and future wellbeing) is a textbook sunk cost fallacy.', 'Arkes, H. R., & Blumer, C. (1985). The psychology of sunk cost. Organizational Behavior and Human Decision Processes.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A person stays in a relationship they''re unhappy in, thinking ''I''ve already put five years into this.'' What bias does this reasoning reflect?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Sunk cost fallacy', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A person stays in a relationship they''re unhappy in, thinking ''I''ve already put five years into this.'' What bias does this reasoning reflect?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Dunning-Kruger effect', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A person stays in a relationship they''re unhappy in, thinking ''I''ve already put five years into this.'' What bias does this reasoning reflect?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Availability heuristic', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A person stays in a relationship they''re unhappy in, thinking ''I''ve already put five years into this.'' What bias does this reasoning reflect?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Anchoring bias', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'Which of these is NOT an example of the sunk cost fallacy?', 'Deciding based on a genuine cost-benefit forecast — not on what''s already been spent — is exactly the rational approach the sunk cost fallacy fails to follow. The other options all involve continuing something purely because of past investment.', 'Arkes, H. R., & Blumer, C. (1985). The psychology of sunk cost. Organizational Behavior and Human Decision Processes.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of these is NOT an example of the sunk cost fallacy?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Cancelling a gym membership after honestly comparing its future cost and benefit', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of these is NOT an example of the sunk cost fallacy?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Finishing a bad meal because you already paid for it', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of these is NOT an example of the sunk cost fallacy?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Continuing a failing project because of money already spent', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of these is NOT an example of the sunk cost fallacy?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Staying in a job you dislike because of years already spent there', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'Studies have found that even pigeons and rodents show sunk-cost-like behavior in experiments. What does this suggest?', 'Some research suggests sunk cost effects may have roots in more basic, even non-human, decision processes tied to persistence and effort — although the human version is also heavily shaped by social and psychological factors like avoiding regret.', 'Arkes, H. R., & Blumer, C. (1985). The psychology of sunk cost. Organizational Behavior and Human Decision Processes.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Studies have found that even pigeons and rodents show sunk-cost-like behavior in experiments. What does this suggest?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'The tendency may have roots in basic, evolved decision processes', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Studies have found that even pigeons and rodents show sunk-cost-like behavior in experiments. What does this suggest?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Animals are immune to all cognitive biases', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Studies have found that even pigeons and rodents show sunk-cost-like behavior in experiments. What does this suggest?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'The sunk cost fallacy is purely a human invention with no biological basis', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Studies have found that even pigeons and rodents show sunk-cost-like behavior in experiments. What does this suggest?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'This finding has been fully disproven', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'Why might admitting a sunk cost was ''wasted'' feel emotionally difficult, even when logically the right move is to stop?', 'Loss aversion and a desire to avoid feeling regret over the wasted investment can make continuing feel emotionally easier than stopping, even though stopping is often the more rational choice going forward.', 'Arkes, H. R., & Blumer, C. (1985). The psychology of sunk cost. Organizational Behavior and Human Decision Processes.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why might admitting a sunk cost was ''wasted'' feel emotionally difficult, even when logically the right move is to stop?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'It can feel like admitting the past investment was a mistake or a loss', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why might admitting a sunk cost was ''wasted'' feel emotionally difficult, even when logically the right move is to stop?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'It has no emotional component at all', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why might admitting a sunk cost was ''wasted'' feel emotionally difficult, even when logically the right move is to stop?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'It always feels easier than continuing', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why might admitting a sunk cost was ''wasted'' feel emotionally difficult, even when logically the right move is to stop?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Sunk Cost Fallacy' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'It''s a purely financial, not psychological, issue', 0, 3);
INSERT INTO lessons (track_id, title, order_index, xp_reward, mastery_threshold) VALUES ((SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'), 'Dunning-Kruger Effect', 5, 10, 70);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'A person who just took one online course confidently claims to be an expert, while a genuine expert in the same field is more cautious about overstating their knowledge. What is this pattern called?', 'This is the Dunning-Kruger effect — people with limited knowledge or skill in an area often overestimate their own competence, partly because the same skills needed to perform well are also needed to accurately judge one''s own performance.', 'Kruger, J., & Dunning, D. (1999). Unskilled and unaware of it: How difficulties in recognizing one''s own incompetence lead to inflated self-assessments. Journal of Personality and Social Psychology.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A person who just took one online course confidently claims to be an expert, while a genuine expert in the same field is more cautious about overstating their knowledge. What is this pattern called?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Dunning-Kruger effect', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A person who just took one online course confidently claims to be an expert, while a genuine expert in the same field is more cautious about overstating their knowledge. What is this pattern called?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Anchoring bias', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A person who just took one online course confidently claims to be an expert, while a genuine expert in the same field is more cautious about overstating their knowledge. What is this pattern called?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Sunk cost fallacy', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A person who just took one online course confidently claims to be an expert, while a genuine expert in the same field is more cautious about overstating their knowledge. What is this pattern called?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Availability heuristic', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'According to the original research, why do low-skill individuals tend to overestimate their competence?', 'The original study proposed that the same skills required to perform a task well are also required to accurately evaluate performance on that task — so a lack of skill also impairs the ability to recognize that lack of skill.', 'Kruger, J., & Dunning, D. (1999). Unskilled and unaware of it: How difficulties in recognizing one''s own incompetence lead to inflated self-assessments. Journal of Personality and Social Psychology.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'According to the original research, why do low-skill individuals tend to overestimate their competence?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'The skills needed to do well are the same skills needed to judge performance accurately', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'According to the original research, why do low-skill individuals tend to overestimate their competence?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'They are naturally more honest than experts', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'According to the original research, why do low-skill individuals tend to overestimate their competence?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'They have been explicitly told they are experts', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'According to the original research, why do low-skill individuals tend to overestimate their competence?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'They spend more time studying than experts', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'What tends to happen to genuine experts'' confidence as their actual competence increases, according to this research?', 'The original study found that highly skilled individuals sometimes slightly underestimate their relative standing, partly because they assume tasks that are easy for them are also easy for others.', 'Kruger, J., & Dunning, D. (1999). Unskilled and unaware of it: How difficulties in recognizing one''s own incompetence lead to inflated self-assessments. Journal of Personality and Social Psychology.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'What tends to happen to genuine experts'' confidence as their actual competence increases, according to this research?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'They sometimes slightly underestimate their own relative skill', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'What tends to happen to genuine experts'' confidence as their actual competence increases, according to this research?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Their confidence always becomes wildly inflated', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'What tends to happen to genuine experts'' confidence as their actual competence increases, according to this research?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'They stop being able to judge their skill at all', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'What tends to happen to genuine experts'' confidence as their actual competence increases, according to this research?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Their confidence has no relationship to their skill', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'scenario', 'A new employee with two weeks of experience confidently tells a 15-year veteran how to do their job. The veteran, despite being far more skilled, hesitates before offering an opinion. What best explains this contrast?', 'This mirrors the classic Dunning-Kruger pattern — limited experience can produce inflated confidence, while deep expertise often comes with a clearer, more humble sense of a field''s genuine complexity and one''s own limitations within it.', 'Kruger, J., & Dunning, D. (1999). Unskilled and unaware of it: How difficulties in recognizing one''s own incompetence lead to inflated self-assessments. Journal of Personality and Social Psychology.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A new employee with two weeks of experience confidently tells a 15-year veteran how to do their job. The veteran, despite being far more skilled, hesitates before offering an opinion. What best explains this contrast?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'The Dunning-Kruger effect', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A new employee with two weeks of experience confidently tells a 15-year veteran how to do their job. The veteran, despite being far more skilled, hesitates before offering an opinion. What best explains this contrast?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'The sunk cost fallacy', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A new employee with two weeks of experience confidently tells a 15-year veteran how to do their job. The veteran, despite being far more skilled, hesitates before offering an opinion. What best explains this contrast?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'The availability heuristic', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A new employee with two weeks of experience confidently tells a 15-year veteran how to do their job. The veteran, despite being far more skilled, hesitates before offering an opinion. What best explains this contrast?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Confirmation bias', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'Which of these is the best way to reduce Dunning-Kruger-style overconfidence in yourself?', 'Seeking honest, specific feedback from people more skilled than you directly targets the core problem — a lack of accurate information about your own performance — rather than relying on internal self-assessment alone.', 'Kruger, J., & Dunning, D. (1999). Unskilled and unaware of it: How difficulties in recognizing one''s own incompetence lead to inflated self-assessments. Journal of Personality and Social Psychology.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of these is the best way to reduce Dunning-Kruger-style overconfidence in yourself?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Actively seek specific, honest feedback from more skilled others', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of these is the best way to reduce Dunning-Kruger-style overconfidence in yourself?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Avoid feedback so your confidence stays high', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of these is the best way to reduce Dunning-Kruger-style overconfidence in yourself?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Only compare yourself to total beginners', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of these is the best way to reduce Dunning-Kruger-style overconfidence in yourself?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Trust your self-assessment completely', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'Is the Dunning-Kruger effect the same thing as simply ''being stupid''?', 'The effect is specifically about the gap between skill and self-assessed skill within a specific domain — it can happen to anyone in an area where they have limited experience, regardless of their general intelligence.', 'Kruger, J., & Dunning, D. (1999). Unskilled and unaware of it: How difficulties in recognizing one''s own incompetence lead to inflated self-assessments. Journal of Personality and Social Psychology.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Is the Dunning-Kruger effect the same thing as simply ''being stupid''?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'No — it''s about a skill/self-assessment gap in a specific domain, not general intelligence', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Is the Dunning-Kruger effect the same thing as simply ''being stupid''?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Yes — only people with low IQ experience it', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Is the Dunning-Kruger effect the same thing as simply ''being stupid''?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Yes — it''s identical to low intelligence in all contexts', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Is the Dunning-Kruger effect the same thing as simply ''being stupid''?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'No — it only applies to people over age 60', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'A common early stage in learning a new skill is a temporary spike in confidence right after gaining just a little bit of knowledge. What is this pattern often called?', 'This pattern is often referred to as the ''peak of Mount Stupid'' colloquially — a burst of confidence after minimal exposure, before deeper learning reveals the true complexity of a subject and confidence dips again.', 'Kruger, J., & Dunning, D. (1999). Unskilled and unaware of it: How difficulties in recognizing one''s own incompetence lead to inflated self-assessments. Journal of Personality and Social Psychology.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A common early stage in learning a new skill is a temporary spike in confidence right after gaining just a little bit of knowledge. What is this pattern often called?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'An early confidence spike, before deeper learning reveals complexity', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A common early stage in learning a new skill is a temporary spike in confidence right after gaining just a little bit of knowledge. What is this pattern often called?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'The final stage of mastering any skill', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A common early stage in learning a new skill is a temporary spike in confidence right after gaining just a little bit of knowledge. What is this pattern often called?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'A permanent state that never changes', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A common early stage in learning a new skill is a temporary spike in confidence right after gaining just a little bit of knowledge. What is this pattern often called?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'A sign of guaranteed future expertise', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101')), 'mcq', 'Why is it important to distinguish the Dunning-Kruger effect from simply being new at something?', 'Being a beginner is not itself a flaw — the issue the effect describes is specifically the mismatch between low skill and high self-assessed confidence, not lack of experience alone. A humble beginner who knows they''re a beginner isn''t experiencing the effect.', 'Kruger, J., & Dunning, D. (1999). Unskilled and unaware of it: How difficulties in recognizing one''s own incompetence lead to inflated self-assessments. Journal of Personality and Social Psychology.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why is it important to distinguish the Dunning-Kruger effect from simply being new at something?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'The effect is about overconfidence relative to skill, not about being new', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why is it important to distinguish the Dunning-Kruger effect from simply being new at something?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'There is no meaningful distinction', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why is it important to distinguish the Dunning-Kruger effect from simply being new at something?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'Being new automatically means you have the effect', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why is it important to distinguish the Dunning-Kruger effect from simply being new at something?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Dunning-Kruger Effect' AND track_id = (SELECT id FROM tracks WHERE slug = 'cognitive-biases-101'))), 'The effect only applies to experienced people', 0, 3);
INSERT INTO tracks (title, slug, description, icon, order_index, is_published) VALUES ('Difficult Conversations', 'difficult-conversations', 'Practical, evidence-based skills for handling feedback, conflict, and disagreement without damaging the relationship.', 'message-circle', 2, 1);
INSERT INTO lessons (track_id, title, order_index, xp_reward, mastery_threshold) VALUES ((SELECT id FROM tracks WHERE slug = 'difficult-conversations'), 'Active Listening Basics', 1, 10, 70);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'A friend is venting about a bad day. Instead of offering advice, you say, ''That sounds really frustrating — tell me more about what happened.'' What listening technique is this?', 'This is reflective listening — acknowledging the other person''s emotion and inviting them to continue, rather than jumping straight to problem-solving, which research shows tends to make people feel more heard and understood.', 'Rogers, C. R., & Farson, R. E. (1957). Active Listening. Industrial Relations Center, University of Chicago.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A friend is venting about a bad day. Instead of offering advice, you say, ''That sounds really frustrating — tell me more about what happened.'' What listening technique is this?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Reflective listening', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A friend is venting about a bad day. Instead of offering advice, you say, ''That sounds really frustrating — tell me more about what happened.'' What listening technique is this?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Anchoring', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A friend is venting about a bad day. Instead of offering advice, you say, ''That sounds really frustrating — tell me more about what happened.'' What listening technique is this?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Confirmation bias', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A friend is venting about a bad day. Instead of offering advice, you say, ''That sounds really frustrating — tell me more about what happened.'' What listening technique is this?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Sunk cost reasoning', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'Which of these is a core component of active listening, according to Carl Rogers'' original framework?', 'Suspending judgment while the other person speaks — rather than mentally preparing a rebuttal — is central to active listening, since it allows genuine understanding before evaluation or response.', 'Rogers, C. R., & Farson, R. E. (1957). Active Listening. Industrial Relations Center, University of Chicago.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of these is a core component of active listening, according to Carl Rogers'' original framework?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Suspending judgment while the other person is speaking', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of these is a core component of active listening, according to Carl Rogers'' original framework?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Planning your response while they''re still talking', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of these is a core component of active listening, according to Carl Rogers'' original framework?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Interrupting to correct inaccuracies immediately', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of these is a core component of active listening, according to Carl Rogers'' original framework?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Changing the subject to something more positive', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'scenario', 'During a conversation, you paraphrase what the other person just said in your own words before responding with your own point. What purpose does this paraphrasing serve?', 'Paraphrasing confirms you''ve correctly understood the other person''s meaning before responding, and signals to them that they were actually heard — both of which reduce miscommunication and defensiveness.', 'Rogers, C. R., & Farson, R. E. (1957). Active Listening. Industrial Relations Center, University of Chicago.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'During a conversation, you paraphrase what the other person just said in your own words before responding with your own point. What purpose does this paraphrasing serve?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'It confirms understanding and signals the person was heard', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'During a conversation, you paraphrase what the other person just said in your own words before responding with your own point. What purpose does this paraphrasing serve?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'It proves you disagree with them', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'During a conversation, you paraphrase what the other person just said in your own words before responding with your own point. What purpose does this paraphrasing serve?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'It ends the conversation faster', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'During a conversation, you paraphrase what the other person just said in your own words before responding with your own point. What purpose does this paraphrasing serve?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'It has no real communicative purpose', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'What''s the difference between listening to respond and listening to understand?', 'Listening to respond means most of your attention is on formulating your next point, while listening to understand means your attention is on genuinely grasping the other person''s meaning first — the latter is the foundation of active listening.', 'Rogers, C. R., & Farson, R. E. (1957). Active Listening. Industrial Relations Center, University of Chicago.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'What''s the difference between listening to respond and listening to understand?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Listening to respond focuses on your reply; listening to understand focuses on their meaning', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'What''s the difference between listening to respond and listening to understand?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'There is no meaningful difference', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'What''s the difference between listening to respond and listening to understand?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Listening to respond is always the better approach', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'What''s the difference between listening to respond and listening to understand?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Listening to understand means staying completely silent forever', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'Which nonverbal behavior most supports active listening in a face-to-face conversation?', 'Consistent eye contact and an open posture signal attentiveness and engagement, both of which are commonly cited nonverbal components that reinforce active listening.', 'Rogers, C. R., & Farson, R. E. (1957). Active Listening. Industrial Relations Center, University of Chicago.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which nonverbal behavior most supports active listening in a face-to-face conversation?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Maintaining eye contact and an open posture', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which nonverbal behavior most supports active listening in a face-to-face conversation?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Checking your phone periodically', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which nonverbal behavior most supports active listening in a face-to-face conversation?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Looking away to appear relaxed', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which nonverbal behavior most supports active listening in a face-to-face conversation?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Crossing your arms and looking down', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'A coworker says, ''I''m fine,'' but their tone and body language suggest otherwise. What would active listening prompt you to do?', 'Active listening involves attending to more than just literal words — noticing tone and body language, and gently checking in, shows genuine attentiveness rather than taking a surface-level answer at face value.', 'Rogers, C. R., & Farson, R. E. (1957). Active Listening. Industrial Relations Center, University of Chicago.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A coworker says, ''I''m fine,'' but their tone and body language suggest otherwise. What would active listening prompt you to do?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Gently acknowledge the mismatch and check in with them', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A coworker says, ''I''m fine,'' but their tone and body language suggest otherwise. What would active listening prompt you to do?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Take the word ''fine'' at face value and move on immediately', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A coworker says, ''I''m fine,'' but their tone and body language suggest otherwise. What would active listening prompt you to do?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Point out that they''re lying', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A coworker says, ''I''m fine,'' but their tone and body language suggest otherwise. What would active listening prompt you to do?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Ignore their tone entirely', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'Why might immediately offering solutions during someone''s emotional venting sometimes backfire?', 'When someone is venting, they often want to feel heard and understood first — jumping straight to solutions can feel like their emotions are being brushed aside or that the listener is trying to end the conversation quickly.', 'Rogers, C. R., & Farson, R. E. (1957). Active Listening. Industrial Relations Center, University of Chicago.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why might immediately offering solutions during someone''s emotional venting sometimes backfire?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'It can feel like their emotions were skipped over rather than heard', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why might immediately offering solutions during someone''s emotional venting sometimes backfire?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Solutions are always unwelcome in every conversation', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why might immediately offering solutions during someone''s emotional venting sometimes backfire?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'It has no effect on how the conversation feels', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why might immediately offering solutions during someone''s emotional venting sometimes backfire?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'It always makes the other person feel better', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'Which of the following is an example of a good open-ended question that supports active listening?', 'Open-ended questions invite the other person to elaborate in their own words, giving you more genuine information and signaling real interest — compared to closed yes/no questions that can shut a conversation down.', 'Rogers, C. R., & Farson, R. E. (1957). Active Listening. Industrial Relations Center, University of Chicago.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of the following is an example of a good open-ended question that supports active listening?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), '''What was that experience like for you?''', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of the following is an example of a good open-ended question that supports active listening?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), '''Are you done talking now?''', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of the following is an example of a good open-ended question that supports active listening?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), '''Isn''t that a bit of an overreaction?''', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of the following is an example of a good open-ended question that supports active listening?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Active Listening Basics' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), '''Did you finish?''', 0, 3);
INSERT INTO lessons (track_id, title, order_index, xp_reward, mastery_threshold) VALUES ((SELECT id FROM tracks WHERE slug = 'difficult-conversations'), 'Giving Difficult Feedback', 2, 10, 70);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'Which is generally better feedback: ''You''re careless with details'' or ''The report had three data errors that changed the conclusion''?', 'Specific, behavior-focused feedback describes an observable action and its impact rather than making a broad judgment about someone''s character, which tends to be more actionable and less likely to trigger defensiveness.', 'Stone, D., Patton, B., & Heen, S. (1999). Difficult Conversations: How to Discuss What Matters Most. Viking.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which is generally better feedback: ''You''re careless with details'' or ''The report had three data errors that changed the conclusion''?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), '''The report had three data errors that changed the conclusion''', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which is generally better feedback: ''You''re careless with details'' or ''The report had three data errors that changed the conclusion''?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), '''You''re careless with details''', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which is generally better feedback: ''You''re careless with details'' or ''The report had three data errors that changed the conclusion''?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Both are equally effective', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which is generally better feedback: ''You''re careless with details'' or ''The report had three data errors that changed the conclusion''?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Neither should ever be said', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'The ''Situation-Behavior-Impact'' feedback model asks you to describe what three things?', 'This widely used model structures feedback around a concrete situation, a specific observed behavior, and the resulting impact — keeping feedback factual and reducing the chance it feels like a personal attack.', 'Center for Creative Leadership. SBI Feedback Model.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'The ''Situation-Behavior-Impact'' feedback model asks you to describe what three things?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'The specific situation, the observed behavior, and its impact', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'The ''Situation-Behavior-Impact'' feedback model asks you to describe what three things?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'The person''s personality, history, and reputation', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'The ''Situation-Behavior-Impact'' feedback model asks you to describe what three things?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Your opinion, your mood, and your goals', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'The ''Situation-Behavior-Impact'' feedback model asks you to describe what three things?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'The weather, the time, and the location', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'scenario', 'A manager wants to give feedback about a missed deadline. Which opening is more likely to keep the other person receptive rather than defensive?', 'Starting with a specific, observable fact (''the deadline was missed by two days'') rather than a broad character judgment (''you''re unreliable'') keeps the conversation focused on the actual event, reducing defensiveness.', 'Stone, D., Patton, B., & Heen, S. (1999). Difficult Conversations: How to Discuss What Matters Most. Viking.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A manager wants to give feedback about a missed deadline. Which opening is more likely to keep the other person receptive rather than defensive?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), '''The deadline was missed by two days — can we talk through what happened?''', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A manager wants to give feedback about a missed deadline. Which opening is more likely to keep the other person receptive rather than defensive?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), '''You''re always unreliable and it''s a real problem.''', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A manager wants to give feedback about a missed deadline. Which opening is more likely to keep the other person receptive rather than defensive?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), '''I guess you just don''t care about this project.''', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A manager wants to give feedback about a missed deadline. Which opening is more likely to keep the other person receptive rather than defensive?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), '''Everyone on the team is annoyed with you.''', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'Why does ''Difficult Conversations'' (Stone, Patton, Heen) recommend separating intent from impact when giving feedback?', 'The authors emphasize that you can only directly observe someone''s impact on you, not their intent — assuming negative intent based only on impact often leads to unfair accusations and unnecessary conflict.', 'Stone, D., Patton, B., & Heen, S. (1999). Difficult Conversations: How to Discuss What Matters Most. Viking.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why does ''Difficult Conversations'' (Stone, Patton, Heen) recommend separating intent from impact when giving feedback?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'You can observe someone''s impact, but you can''t actually know their intent', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why does ''Difficult Conversations'' (Stone, Patton, Heen) recommend separating intent from impact when giving feedback?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Intent and impact are always identical', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why does ''Difficult Conversations'' (Stone, Patton, Heen) recommend separating intent from impact when giving feedback?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Impact never matters in feedback', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why does ''Difficult Conversations'' (Stone, Patton, Heen) recommend separating intent from impact when giving feedback?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Intent should always be assumed to be negative', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'What''s a key benefit of giving feedback promptly rather than waiting weeks or months?', 'Timely feedback is tied to a specific, recent, and clearly recalled event, which makes the conversation more concrete and actionable than raising an issue long after the details have faded from memory.', 'Center for Creative Leadership. SBI Feedback Model.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'What''s a key benefit of giving feedback promptly rather than waiting weeks or months?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'The event is still fresh and specific in everyone''s memory', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'What''s a key benefit of giving feedback promptly rather than waiting weeks or months?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'It allows you to build a longer list of complaints', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'What''s a key benefit of giving feedback promptly rather than waiting weeks or months?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Delayed feedback is always more effective', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'What''s a key benefit of giving feedback promptly rather than waiting weeks or months?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'There is no benefit to timing', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'A common feedback structure sandwiches criticism between two compliments (the ''feedback sandwich''). What''s a known downside of this approach?', 'Research and practitioner experience suggest that if used too predictably, the sandwich technique can make the positive comments feel insincere or make the person tune out, waiting for the ''real'' criticism in the middle.', 'Center for Creative Leadership. SBI Feedback Model.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A common feedback structure sandwiches criticism between two compliments (the ''feedback sandwich''). What''s a known downside of this approach?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'The praise can start to feel insincere or predictable', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A common feedback structure sandwiches criticism between two compliments (the ''feedback sandwich''). What''s a known downside of this approach?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'It always guarantees the feedback is ignored entirely', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A common feedback structure sandwiches criticism between two compliments (the ''feedback sandwich''). What''s a known downside of this approach?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'It has been proven to have no downsides at all', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A common feedback structure sandwiches criticism between two compliments (the ''feedback sandwich''). What''s a known downside of this approach?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'It legally cannot be used in workplaces', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'Which question is most useful to ask yourself before giving critical feedback?', 'Clarifying your goal helps ensure the feedback is constructive and future-focused, rather than driven by frustration or a need to vent, which tends to produce more useful and better-received conversations.', 'Stone, D., Patton, B., & Heen, S. (1999). Difficult Conversations: How to Discuss What Matters Most. Viking.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which question is most useful to ask yourself before giving critical feedback?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), '''What outcome am I hoping this feedback leads to?''', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which question is most useful to ask yourself before giving critical feedback?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), '''How can I make this feel as bad as possible for them?''', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which question is most useful to ask yourself before giving critical feedback?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), '''Can I avoid saying this at all costs?''', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which question is most useful to ask yourself before giving critical feedback?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), '''How can I bring up every past mistake at once?''', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'After giving feedback, what does ''Difficult Conversations'' suggest doing to make it a two-way conversation rather than a one-way lecture?', 'Inviting the other person''s perspective turns feedback into a dialogue rather than a monologue, often surfacing context you didn''t have and making the person more likely to genuinely engage with the feedback.', 'Stone, D., Patton, B., & Heen, S. (1999). Difficult Conversations: How to Discuss What Matters Most. Viking.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'After giving feedback, what does ''Difficult Conversations'' suggest doing to make it a two-way conversation rather than a one-way lecture?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Ask for their perspective on what happened', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'After giving feedback, what does ''Difficult Conversations'' suggest doing to make it a two-way conversation rather than a one-way lecture?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'End the conversation immediately after speaking', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'After giving feedback, what does ''Difficult Conversations'' suggest doing to make it a two-way conversation rather than a one-way lecture?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Repeat the same point louder', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'After giving feedback, what does ''Difficult Conversations'' suggest doing to make it a two-way conversation rather than a one-way lecture?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Giving Difficult Feedback' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Avoid letting them respond at all', 0, 3);
INSERT INTO lessons (track_id, title, order_index, xp_reward, mastery_threshold) VALUES ((SELECT id FROM tracks WHERE slug = 'difficult-conversations'), 'De-escalating Conflict', 3, 10, 70);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'During a heated argument, one person''s voice starts rising and their words speed up. What physiological state does this often reflect?', 'This pattern often reflects what researcher John Gottman calls ''flooding'' — a state of physiological arousal where rational, measured discussion becomes difficult, often signaling it''s time to pause rather than push forward.', 'Gottman, J. M., & Silver, N. (1999). The Seven Principles for Making Marriage Work. Crown Publishers.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'During a heated argument, one person''s voice starts rising and their words speed up. What physiological state does this often reflect?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Physiological flooding / heightened arousal', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'During a heated argument, one person''s voice starts rising and their words speed up. What physiological state does this often reflect?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Complete calm and rational thought', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'During a heated argument, one person''s voice starts rising and their words speed up. What physiological state does this often reflect?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'The sunk cost fallacy', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'During a heated argument, one person''s voice starts rising and their words speed up. What physiological state does this often reflect?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Confirmation bias', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'When someone is ''flooded'' during an argument, what does research suggest is often the most effective immediate step?', 'Taking a structured break — often suggested as at least 20 minutes — allows physiological arousal to settle before productive conversation can resume, since attempts to reason during flooding tend to be unproductive.', 'Gottman, J. M., & Silver, N. (1999). The Seven Principles for Making Marriage Work. Crown Publishers.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'When someone is ''flooded'' during an argument, what does research suggest is often the most effective immediate step?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Take a break to let physiological arousal settle before continuing', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'When someone is ''flooded'' during an argument, what does research suggest is often the most effective immediate step?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Raise your voice louder to be heard', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'When someone is ''flooded'' during an argument, what does research suggest is often the most effective immediate step?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Bring up unrelated past arguments', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'When someone is ''flooded'' during an argument, what does research suggest is often the most effective immediate step?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Keep pushing until the issue is resolved immediately', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'scenario', 'In a disagreement, one partner says: ''You NEVER listen to me, you ALWAYS do this.'' What communication pattern is this, and why does it tend to escalate conflict?', 'Absolute language like ''always'' and ''never'' tends to feel like a sweeping character attack rather than feedback about a specific instance, which often triggers defensiveness and escalates rather than resolves the disagreement.', 'Gottman, J. M., & Silver, N. (1999). The Seven Principles for Making Marriage Work. Crown Publishers.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'In a disagreement, one partner says: ''You NEVER listen to me, you ALWAYS do this.'' What communication pattern is this, and why does it tend to escalate conflict?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Absolute language (''always''/''never'') that feels like a sweeping attack', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'In a disagreement, one partner says: ''You NEVER listen to me, you ALWAYS do this.'' What communication pattern is this, and why does it tend to escalate conflict?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Calm, specific, de-escalating language', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'In a disagreement, one partner says: ''You NEVER listen to me, you ALWAYS do this.'' What communication pattern is this, and why does it tend to escalate conflict?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'A neutral statement of fact', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'In a disagreement, one partner says: ''You NEVER listen to me, you ALWAYS do this.'' What communication pattern is this, and why does it tend to escalate conflict?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Active listening', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'Which of these is an example of a ''soft startup'' to a difficult conversation, as opposed to a harsh one?', 'A soft startup raises the issue calmly, focuses on your own experience with an ''I'' statement, and avoids blame — research shows how a conversation begins strongly predicts how it will end.', 'Gottman, J. M., & Silver, N. (1999). The Seven Principles for Making Marriage Work. Crown Publishers.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of these is an example of a ''soft startup'' to a difficult conversation, as opposed to a harsh one?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), '''I felt overlooked when the decision was made without me — can we talk about it?''', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of these is an example of a ''soft startup'' to a difficult conversation, as opposed to a harsh one?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), '''You always shut me out of every decision!''', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of these is an example of a ''soft startup'' to a difficult conversation, as opposed to a harsh one?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), '''Why do you constantly disrespect me?''', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of these is an example of a ''soft startup'' to a difficult conversation, as opposed to a harsh one?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), '''You clearly don''t care what I think.''', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'What does it mean to ''stay on the issue'' during a conflict, rather than letting it expand?', 'Staying focused on the specific, current issue — rather than dragging in unrelated grievances from the past — keeps the conversation manageable and prevents it from spiraling into a much larger, harder-to-resolve conflict.', 'Gottman, J. M., & Silver, N. (1999). The Seven Principles for Making Marriage Work. Crown Publishers.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'What does it mean to ''stay on the issue'' during a conflict, rather than letting it expand?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Avoiding bringing in unrelated past grievances', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'What does it mean to ''stay on the issue'' during a conflict, rather than letting it expand?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Bringing up every past disagreement at once', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'What does it mean to ''stay on the issue'' during a conflict, rather than letting it expand?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Refusing to discuss the actual issue at all', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'What does it mean to ''stay on the issue'' during a conflict, rather than letting it expand?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Changing the subject as often as possible', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'During a tense conversation, briefly acknowledging the other person''s point (''I see why that would be frustrating'') before responding tends to have what effect?', 'Acknowledgment signals that the other person''s perspective has registered, which can lower defensiveness and make them more receptive to hearing your side, even if you ultimately disagree.', 'Gottman, J. M., & Silver, N. (1999). The Seven Principles for Making Marriage Work. Crown Publishers.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'During a tense conversation, briefly acknowledging the other person''s point (''I see why that would be frustrating'') before responding tends to have what effect?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'It tends to lower defensiveness and increase receptiveness', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'During a tense conversation, briefly acknowledging the other person''s point (''I see why that would be frustrating'') before responding tends to have what effect?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'It always means you''re agreeing with everything they said', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'During a tense conversation, briefly acknowledging the other person''s point (''I see why that would be frustrating'') before responding tends to have what effect?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'It has no effect on the conversation', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'During a tense conversation, briefly acknowledging the other person''s point (''I see why that would be frustrating'') before responding tends to have what effect?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'It usually escalates the conflict further', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'Which of Gottman''s research-identified behaviors is considered especially damaging to a relationship during conflict?', 'Contempt — communicating disgust or superiority, such as through sarcasm, eye-rolling, or mockery — was found in Gottman''s research to be a particularly strong predictor of relationship breakdown, more so than most other negative behaviors.', 'Gottman, J. M., & Silver, N. (1999). The Seven Principles for Making Marriage Work. Crown Publishers.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of Gottman''s research-identified behaviors is considered especially damaging to a relationship during conflict?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Contempt (e.g. sarcasm, mockery, eye-rolling)', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of Gottman''s research-identified behaviors is considered especially damaging to a relationship during conflict?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Asking a clarifying question', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of Gottman''s research-identified behaviors is considered especially damaging to a relationship during conflict?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Taking a short break to cool down', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of Gottman''s research-identified behaviors is considered especially damaging to a relationship during conflict?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Using a specific, calm ''I'' statement', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'Why might agreeing on a specific time to revisit a heated topic (rather than dropping it entirely) be more effective than either continuing to argue or avoiding it forever?', 'Scheduling a specific time to return to the issue respects the need to cool down while still ensuring the topic actually gets resolved, avoiding both unproductive escalation and unresolved resentment from permanent avoidance.', 'Gottman, J. M., & Silver, N. (1999). The Seven Principles for Making Marriage Work. Crown Publishers.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why might agreeing on a specific time to revisit a heated topic (rather than dropping it entirely) be more effective than either continuing to argue or avoiding it forever?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'It allows time to cool down while ensuring the issue still gets addressed', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why might agreeing on a specific time to revisit a heated topic (rather than dropping it entirely) be more effective than either continuing to argue or avoiding it forever?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'It guarantees the issue will never come up again', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why might agreeing on a specific time to revisit a heated topic (rather than dropping it entirely) be more effective than either continuing to argue or avoiding it forever?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'It is exactly the same as continuing to argue right now', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why might agreeing on a specific time to revisit a heated topic (rather than dropping it entirely) be more effective than either continuing to argue or avoiding it forever?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'De-escalating Conflict' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'It has no real benefit over just avoiding the topic forever', 0, 3);
INSERT INTO lessons (track_id, title, order_index, xp_reward, mastery_threshold) VALUES ((SELECT id FROM tracks WHERE slug = 'difficult-conversations'), 'Setting Healthy Boundaries', 4, 10, 70);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'A coworker frequently asks you to take on extra tasks outside your role. You say, ''I can''t take that on right now, but I can help you find someone who can.'' What is this an example of?', 'This is a clear, respectful boundary — it states a limit directly without over-explaining or apologizing excessively, while still offering a constructive alternative, which research on assertiveness identifies as an effective approach.', 'Alberti, R., & Emmons, M. (2017). Your Perfect Right: Assertiveness and Equality in Your Life and Relationships. New Harbinger Publications.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A coworker frequently asks you to take on extra tasks outside your role. You say, ''I can''t take that on right now, but I can help you find someone who can.'' What is this an example of?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'A clear, respectful boundary', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A coworker frequently asks you to take on extra tasks outside your role. You say, ''I can''t take that on right now, but I can help you find someone who can.'' What is this an example of?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'The sunk cost fallacy', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A coworker frequently asks you to take on extra tasks outside your role. You say, ''I can''t take that on right now, but I can help you find someone who can.'' What is this an example of?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Confirmation bias', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A coworker frequently asks you to take on extra tasks outside your role. You say, ''I can''t take that on right now, but I can help you find someone who can.'' What is this an example of?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Contempt', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'What is the key difference between assertiveness and aggressiveness when setting a boundary?', 'Assertiveness expresses your own needs clearly while still respecting the other person, whereas aggressiveness disregards or violates the other person''s needs and rights in the process of expressing your own.', 'Alberti, R., & Emmons, M. (2017). Your Perfect Right: Assertiveness and Equality in Your Life and Relationships. New Harbinger Publications.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'What is the key difference between assertiveness and aggressiveness when setting a boundary?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Assertiveness respects the other person''s rights; aggressiveness disregards them', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'What is the key difference between assertiveness and aggressiveness when setting a boundary?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'They are exactly the same thing', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'What is the key difference between assertiveness and aggressiveness when setting a boundary?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Aggressiveness is always more effective long-term', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'What is the key difference between assertiveness and aggressiveness when setting a boundary?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Assertiveness means avoiding the topic entirely', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'scenario', 'Someone repeatedly cancels plans on you last-minute. Which response best sets a boundary without being either passive or aggressive?', 'This response states the impact clearly and proposes a specific, reasonable boundary going forward — it''s direct and respectful, rather than silently resentful (passive) or attacking the person''s character (aggressive).', 'Alberti, R., & Emmons, M. (2017). Your Perfect Right: Assertiveness and Equality in Your Life and Relationships. New Harbinger Publications.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Someone repeatedly cancels plans on you last-minute. Which response best sets a boundary without being either passive or aggressive?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), '''When plans get cancelled last-minute, it''s hard for me to plan my time. Can we agree on more notice going forward?''', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Someone repeatedly cancels plans on you last-minute. Which response best sets a boundary without being either passive or aggressive?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Saying nothing and quietly feeling resentful each time', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Someone repeatedly cancels plans on you last-minute. Which response best sets a boundary without being either passive or aggressive?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), '''You''re the most unreliable person I know.''', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Someone repeatedly cancels plans on you last-minute. Which response best sets a boundary without being either passive or aggressive?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Cancelling on them without explanation as payback', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'Why do many people feel guilty when first setting a boundary, even when the boundary is reasonable?', 'People who are used to prioritizing others'' needs or avoiding conflict often initially feel guilt when asserting their own needs, even though maintaining reasonable boundaries is a normal and healthy part of relationships.', 'Alberti, R., & Emmons, M. (2017). Your Perfect Right: Assertiveness and Equality in Your Life and Relationships. New Harbinger Publications.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why do many people feel guilty when first setting a boundary, even when the boundary is reasonable?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'They may be unused to prioritizing their own needs over avoiding conflict', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why do many people feel guilty when first setting a boundary, even when the boundary is reasonable?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'All boundaries are inherently selfish and wrong', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why do many people feel guilty when first setting a boundary, even when the boundary is reasonable?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Guilt means the boundary must be unreasonable', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why do many people feel guilty when first setting a boundary, even when the boundary is reasonable?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'It only happens to people with no self-respect', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'A boundary is best understood as a statement about what?', 'Effective boundaries focus on what you will or won''t do — something within your control — rather than trying to dictate or control someone else''s behavior directly, which they may or may not choose to change.', 'Alberti, R., & Emmons, M. (2017). Your Perfect Right: Assertiveness and Equality in Your Life and Relationships. New Harbinger Publications.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A boundary is best understood as a statement about what?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'What you will or won''t do — not a demand for someone else to change', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A boundary is best understood as a statement about what?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'A demand that controls someone else''s behavior directly', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A boundary is best understood as a statement about what?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'A punishment for past behavior', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'A boundary is best understood as a statement about what?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'A permanent, one-time statement that never needs restating', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'When someone reacts negatively to a reasonable boundary you''ve set, what does assertiveness research suggest about staying firm?', 'A negative reaction to a reasonable boundary doesn''t automatically mean the boundary was wrong — it''s common for people to initially resist a change to a dynamic they were previously benefiting from, and consistency matters.', 'Alberti, R., & Emmons, M. (2017). Your Perfect Right: Assertiveness and Equality in Your Life and Relationships. New Harbinger Publications.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'When someone reacts negatively to a reasonable boundary you''ve set, what does assertiveness research suggest about staying firm?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'A negative reaction doesn''t automatically mean the boundary was wrong', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'When someone reacts negatively to a reasonable boundary you''ve set, what does assertiveness research suggest about staying firm?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'You should always immediately abandon the boundary', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'When someone reacts negatively to a reasonable boundary you''ve set, what does assertiveness research suggest about staying firm?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Negative reactions never happen to reasonable boundaries', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'When someone reacts negatively to a reasonable boundary you''ve set, what does assertiveness research suggest about staying firm?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'You should apologize repeatedly until they''re comfortable', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'Which phrase is an example of an over-explained, apology-heavy way of setting a boundary, which assertiveness training generally advises against?', 'Excessive apologizing and over-justifying can undermine a boundary and signal uncertainty — assertiveness training generally recommends stating the boundary clearly and directly, without needing extensive justification.', 'Alberti, R., & Emmons, M. (2017). Your Perfect Right: Assertiveness and Equality in Your Life and Relationships. New Harbinger Publications.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which phrase is an example of an over-explained, apology-heavy way of setting a boundary, which assertiveness training generally advises against?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), '''I''m SO sorry, I feel terrible, I know this is probably unreasonable, but maybe possibly I can''t do this?''', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which phrase is an example of an over-explained, apology-heavy way of setting a boundary, which assertiveness training generally advises against?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), '''I''m not able to take this on right now.''', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which phrase is an example of an over-explained, apology-heavy way of setting a boundary, which assertiveness training generally advises against?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), '''That doesn''t work for me — here''s what I can do instead.''', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which phrase is an example of an over-explained, apology-heavy way of setting a boundary, which assertiveness training generally advises against?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), '''I need to say no to this one.''', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'Why might setting a boundary at work (e.g. not answering emails after hours) actually improve a working relationship over time?', 'Clear boundaries reduce built-up resentment and burnout, which tend to erode relationships over time — a sustainable, respected boundary often supports a healthier, more consistent working relationship than one built on quiet overextension.', 'Alberti, R., & Emmons, M. (2017). Your Perfect Right: Assertiveness and Equality in Your Life and Relationships. New Harbinger Publications.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why might setting a boundary at work (e.g. not answering emails after hours) actually improve a working relationship over time?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'It can reduce resentment and burnout that would otherwise erode the relationship', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why might setting a boundary at work (e.g. not answering emails after hours) actually improve a working relationship over time?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'It guarantees the other person will never be frustrated again', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why might setting a boundary at work (e.g. not answering emails after hours) actually improve a working relationship over time?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'It has no effect on the relationship either way', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why might setting a boundary at work (e.g. not answering emails after hours) actually improve a working relationship over time?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Setting Healthy Boundaries' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'It always damages the relationship permanently', 0, 3);
INSERT INTO lessons (track_id, title, order_index, xp_reward, mastery_threshold) VALUES ((SELECT id FROM tracks WHERE slug = 'difficult-conversations'), 'Navigating Disagreement Productively', 5, 10, 70);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'Two coworkers disagree on a project approach. Instead of trying to ''win,'' one says, ''Help me understand why you think that approach works better.'' What does this reflect?', 'This reflects a curiosity-based approach to disagreement — seeking to understand the other person''s reasoning rather than immediately defending your own position, which tends to lead to more productive outcomes than a purely adversarial stance.', 'Stone, D., Patton, B., & Heen, S. (1999). Difficult Conversations: How to Discuss What Matters Most. Viking.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Two coworkers disagree on a project approach. Instead of trying to ''win,'' one says, ''Help me understand why you think that approach works better.'' What does this reflect?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'A curiosity-based approach to disagreement', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Two coworkers disagree on a project approach. Instead of trying to ''win,'' one says, ''Help me understand why you think that approach works better.'' What does this reflect?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Avoidance of the disagreement entirely', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Two coworkers disagree on a project approach. Instead of trying to ''win,'' one says, ''Help me understand why you think that approach works better.'' What does this reflect?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'The sunk cost fallacy', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Two coworkers disagree on a project approach. Instead of trying to ''win,'' one says, ''Help me understand why you think that approach works better.'' What does this reflect?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Contempt', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'What is the difference between the ''what happened'' conversation and the ''feelings'' conversation in a disagreement, according to Difficult Conversations?', 'The authors describe every difficult conversation as layered — one part is about facts and differing interpretations of events, and a separate part is about the emotions involved — treating these as one blurred conversation often causes confusion.', 'Stone, D., Patton, B., & Heen, S. (1999). Difficult Conversations: How to Discuss What Matters Most. Viking.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'What is the difference between the ''what happened'' conversation and the ''feelings'' conversation in a disagreement, according to Difficult Conversations?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'One is about facts/interpretations, the other is about the emotions involved', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'What is the difference between the ''what happened'' conversation and the ''feelings'' conversation in a disagreement, according to Difficult Conversations?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'They are the exact same conversation', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'What is the difference between the ''what happened'' conversation and the ''feelings'' conversation in a disagreement, according to Difficult Conversations?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'The feelings conversation should always be avoided', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'What is the difference between the ''what happened'' conversation and the ''feelings'' conversation in a disagreement, according to Difficult Conversations?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Only the ''what happened'' conversation matters', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'scenario', 'In a disagreement about a shared decision, one person says, ''Maybe we''re both seeing different parts of this — what am I missing from your side?'' Why is this framing effective?', 'This framing treats the disagreement as a shared puzzle to solve together rather than a battle to win, which tends to lower defensiveness and open the door to a more collaborative, productive conversation.', 'Stone, D., Patton, B., & Heen, S. (1999). Difficult Conversations: How to Discuss What Matters Most. Viking.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'In a disagreement about a shared decision, one person says, ''Maybe we''re both seeing different parts of this — what am I missing from your side?'' Why is this framing effective?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'It frames the disagreement as a shared puzzle rather than a battle', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'In a disagreement about a shared decision, one person says, ''Maybe we''re both seeing different parts of this — what am I missing from your side?'' Why is this framing effective?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'It proves the other person is wrong', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'In a disagreement about a shared decision, one person says, ''Maybe we''re both seeing different parts of this — what am I missing from your side?'' Why is this framing effective?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'It ends the conversation immediately', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'In a disagreement about a shared decision, one person says, ''Maybe we''re both seeing different parts of this — what am I missing from your side?'' Why is this framing effective?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'It has no effect on how the conversation unfolds', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'Why do two people often walk away from the same event with genuinely different accounts of what happened?', 'Each person''s account is shaped by their own vantage point, assumptions, and selective attention — this doesn''t necessarily mean one person is lying, but that each has a partial, subjective interpretation of the same events.', 'Stone, D., Patton, B., & Heen, S. (1999). Difficult Conversations: How to Discuss What Matters Most. Viking.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why do two people often walk away from the same event with genuinely different accounts of what happened?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Each person''s account is shaped by their own vantage point and assumptions', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why do two people often walk away from the same event with genuinely different accounts of what happened?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'One of them must always be lying', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why do two people often walk away from the same event with genuinely different accounts of what happened?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Memory is always 100% objective and accurate', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Why do two people often walk away from the same event with genuinely different accounts of what happened?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'This never actually happens in real conversations', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'Which mindset shift helps most when entering a disagreement you expect to be difficult?', 'Approaching the conversation with curiosity about the other person''s perspective, rather than a fixed goal of proving them wrong, tends to keep the conversation more open and productive, according to conflict communication research.', 'Stone, D., Patton, B., & Heen, S. (1999). Difficult Conversations: How to Discuss What Matters Most. Viking.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which mindset shift helps most when entering a disagreement you expect to be difficult?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Approaching it with curiosity about their perspective, not just proving your point', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which mindset shift helps most when entering a disagreement you expect to be difficult?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Deciding in advance that you must win at all costs', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which mindset shift helps most when entering a disagreement you expect to be difficult?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Avoiding the conversation until the issue resolves itself', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which mindset shift helps most when entering a disagreement you expect to be difficult?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Assuming the other person has bad intentions', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'During a disagreement, saying ''I'' statements (e.g. ''I felt confused by that decision'') rather than ''you'' statements (e.g. ''you confused everyone'') tends to have what effect?', '''I'' statements describe your own experience and are harder to argue with or feel attacked by, while ''you'' statements can sound like accusations, often triggering defensiveness rather than open dialogue.', 'Gottman, J. M., & Silver, N. (1999). The Seven Principles for Making Marriage Work. Crown Publishers.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'During a disagreement, saying ''I'' statements (e.g. ''I felt confused by that decision'') rather than ''you'' statements (e.g. ''you confused everyone'') tends to have what effect?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), '''I'' statements tend to reduce defensiveness compared to ''you'' statements', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'During a disagreement, saying ''I'' statements (e.g. ''I felt confused by that decision'') rather than ''you'' statements (e.g. ''you confused everyone'') tends to have what effect?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'There''s no meaningful difference between the two', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'During a disagreement, saying ''I'' statements (e.g. ''I felt confused by that decision'') rather than ''you'' statements (e.g. ''you confused everyone'') tends to have what effect?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), '''You'' statements are always more effective', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'During a disagreement, saying ''I'' statements (e.g. ''I felt confused by that decision'') rather than ''you'' statements (e.g. ''you confused everyone'') tends to have what effect?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), '''I'' statements always end the disagreement instantly', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'Is it necessary to reach full agreement for a difficult conversation to be considered successful?', 'Many communication frameworks emphasize that mutual understanding — each person clearly grasping the other''s perspective — is itself a valuable and often realistic outcome, even when full agreement isn''t reached.', 'Stone, D., Patton, B., & Heen, S. (1999). Difficult Conversations: How to Discuss What Matters Most. Viking.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Is it necessary to reach full agreement for a difficult conversation to be considered successful?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'No — mutual understanding alone can be a valuable, successful outcome', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Is it necessary to reach full agreement for a difficult conversation to be considered successful?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Yes — anything short of full agreement is a failure', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Is it necessary to reach full agreement for a difficult conversation to be considered successful?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Yes — otherwise the relationship is permanently damaged', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Is it necessary to reach full agreement for a difficult conversation to be considered successful?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'No — the conversation should always be avoided instead', 0, 3);
INSERT INTO questions (lesson_id, type, prompt, explanation, source_citation) VALUES ((SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations')), 'mcq', 'Which of these is the healthiest way to close out a disagreement where both sides still see it differently?', 'Explicitly naming that both perspectives are understood, even without full agreement, closes the conversation respectfully and avoids the false pressure of forcing artificial consensus.', 'Stone, D., Patton, B., & Heen, S. (1999). Difficult Conversations: How to Discuss What Matters Most. Viking.');
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of these is the healthiest way to close out a disagreement where both sides still see it differently?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), '''I understand your view better now, even though we still see it differently — thanks for talking it through.''', 1, 0);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of these is the healthiest way to close out a disagreement where both sides still see it differently?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Pretending to agree just to end the conversation', 0, 1);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of these is the healthiest way to close out a disagreement where both sides still see it differently?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Refusing to speak to them again', 0, 2);
INSERT INTO question_options (question_id, label, is_correct, order_index) VALUES ((SELECT id FROM questions WHERE prompt = 'Which of these is the healthiest way to close out a disagreement where both sides still see it differently?' AND lesson_id = (SELECT id FROM lessons WHERE title = 'Navigating Disagreement Productively' AND track_id = (SELECT id FROM tracks WHERE slug = 'difficult-conversations'))), 'Repeating your original point louder until they give in', 0, 3);
